import QtQuick
import Quickshell.Hyprland
import Quickshell.Io
import QtQuick
import QtQuick.Layouts

Scope {
  id: root
  property string time

  Variants {
    model: Quickshell.screens

    PanelWindow {
      required property var modelData
      screen: modelData

      anchors {
        top: false
        left: true
        right: true
        bottom: true
      }
      implicitHeight: 30
      margins{
        top: 0
        left: 0
        right: 0
      }

        Rectangle {
          id: bar
          anchors.fill: parent
          color: "#000000"
          radius: 0
          RowLayout {
            id: layout
            spacing: 0
            anchors.fill: parent
            Text {
              color: "#ffffff"
              Layout.alignment: Qt.AlignRight
              anchors.right: parent
              text: root.time
            }
          }
        }
    }
  }

  Process {
    id: dateProc
    command: ["date"]
    running: true

    stdout: StdioCollector {
      onStreamFinished: root.time = this.text
    }
  }

  Timer {
    interval: 1000
    running: true
    repeat: true
    onTriggered: dateProc.running = true
  }
}

